import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void typicalMultiChar() {
        assertEquals("aaabbc", new Solution().decode("a3b2c1"));
    }

    @Test
    void multiDigitCount() {
        assertEquals("xxxxxxxxxxyy", new Solution().decode("x10y2"));
    }

    @Test
    void singleCharCountOne() {
        assertEquals("z", new Solution().decode("z1"));
    }

    @Test
    void emptyInput() {
        assertEquals("", new Solution().decode(""));
    }

    @Test
    void singleRunLargeCount() {
        assertEquals("aaaaa", new Solution().decode("a5"));
    }

    @Test
    void manyDistinctChars() {
        assertEquals("abcde", new Solution().decode("a1b1c1d1e1"));
    }

    @Test
    void largeCountFollowedBySmall() {
        // 100 b's then 1 c
        StringBuilder expected = new StringBuilder();
        for (int i = 0; i < 100; i++) expected.append('b');
        expected.append('c');
        assertEquals(expected.toString(), new Solution().decode("b100c1"));
    }
}
